var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"요즘 아카데미에서 카운터즈 레거시 얘기가 끊이질 않네요.","JPN":"最近アカデミーではカウンターズ・レガシーの話が絶えませんね。","ENG":"Everyone seems to be talking about Counters Legacy at the Academy these days.","TWN":"最近學院裡關於制裁者的遺產的討論不斷呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"이렇게나 많은 학생들이 참여하게 될 줄은 몰랐어요.","JPN":"こんなにたくさんの生徒たちが参加してくれるとは思いませんでした。","ENG":"I didn't expect so many students to participate in it.","TWN":"沒想到會有這麼多學生參與。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아하하, 그럼요. 제가 참여한 프로젝트인데 당연한 결과죠.","JPN":"あはは、私が参加したプロジェクトですから当然の結果です。","ENG":"Ah hah hah, of course, they would. It's a project that I'm involved in.","TWN":"哈哈哈，當然了。這是我參與的項目，結果自然是這樣的。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후훗, 나이엘이 상위 랭크에 들어간 덕분일까요?","JPN":"ふふ、ナイエルが上位ランキングに入ったおかげでしょうか。","ENG":"Haha. Maybe it's also due to Naielle's high rank?","TWN":"呵呵，是因為奈爾進入前段班的緣故嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아~ 맞아요. 그 녀석, 엔간한 퀘스트는 그새 다 클리어했더라고요?","JPN":"あ～そうですね。あいつ、大抵のクエストはもう全部クリアしたみたいですね。","ENG":"Oh, that's right. She seems to have cleared most quests in a matter of days.","TWN":"啊～對了。那傢伙，居然已經把一般的任務都完成了？"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"열심히 하는 건 좋지만 수업을 빼먹진 않았으면 좋겠는데.","JPN":"頑張るのはいいけど、授業はサボらないでほしいんですが……","ENG":"I admire her commitment, but I wish she didn't skip class.","TWN":"努力是好事，但希望她不要蹺課。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"열심이야…… 수업 때도.","JPN":"頑張ってる……授業も。","ENG":"She puts in the work... even in class.","TWN":"她很努力……在上課的時候也是。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그래? 조금 오만하게 굴진 않니?","JPN":"そう？　少し傲慢な態度じゃない？","ENG":"Really? But isn't she a little arrogant?","TWN":"是嗎？你不覺得她這樣有點傲慢嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"음…….","JPN":"ん……","ENG":"Um...","TWN":"嗯……"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"뭐, 뭐야?! 몬스터들이 알아서 피해 가잖아?!","JPN":"な、なんだ！？　モンスターのほうから逃げていく！","ENG":"H-huh?! The monsters are avoiding us!","TWN":"怎，怎麼回事？！怪物們自己躲開了？！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L18_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"나이엘 때문인 것 같아. 그냥 서 있기만 하는데도 엄청난 기백이야!","JPN":"ナイエルのせいだと思う。ただ立ってるだけでものすごい気迫を感じる……！","ENG":"I think it's you, Naielle. You're just standing there, but your aura seems to scare them off!","TWN":"好像是因為奈爾，她只是站在那裡就有一種非凡的氣勢！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"하하, 쬐그만 몬스터들이 기습한다고 내가 눈 하나 깜짝할 것 같아?","JPN":"あはは、ちっちゃいモンスターごときに奇襲を仕掛けられても、どうってことないわ！","ENG":"Haha! You think a couple of puny monsters ambushing me will make me flinch?","TWN":"哈哈，這些小怪來偷襲，你看我會眨一下眼嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"니들은 하나도 재미없어! 난 그 재수 없는 금발 녀석을 뛰어넘어야 한다고!","JPN":"あんたたちはつまんないのよ！　私はあの金髪を乗り越えなきゃいけないの！","ENG":"You're all no fun! I need to surpass that smug blondie!","TWN":"你們一點都不好玩！我一定要超越那個討厭的金髮！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"정말 대단해! 근데 너도 금발이잖아……?\xA0","JPN":"すごい！　でもナイエルも金髪じゃ……\xA0","ENG":"You're amazing! But, aren't you also a blonde...?\xA0","TWN":"真的好厲害！不過你也是金髮吧……？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"니들은 오랜만에 나와놓고 그런 헛소리나 하는 거야?!","JPN":"あんたたち、久しぶりに来ておいてそんなこと言ってる暇あるの！？","ENG":"You make your appearance after a long break, and you're already talking nonsense?!","TWN":"你們好不容易出來一次，就在這裡胡說八道？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"그렇게 못 믿겠으면 보여 줘야겠지.","JPN":"信じられないなら見せてやるしかないわね。","ENG":"If you don't believe me, then I'll just have to show you.","TWN":"如果實在不信的話，就給你看看吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"내가 진심을 보이면 어떻게 되는지!","JPN":"私が本気を出すとどうなるのか！","ENG":"Watch what happens when I give it my all!","TWN":"如果我展現出真心會怎麼樣！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"UI_BASE_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……조금은.","JPN":"……少し。","ENG":"...Maybe a little.","TWN":"……有些。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L29_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"어휴~ 어찌나 까불던지 정말 확 쥐어박고 싶을 정도라니까요?","JPN":"もう～調子に乗っちゃって、一発食らわせてやりたいくらいです。","ENG":"Ugh... Sometimes, she's so annoying that I want to smack her on the head.","TWN":"哎呀～真是太囂張了，真想狠狠揍她一頓呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하…… 조금은 주의를 줘야겠네요.","JPN":"あはは……ちょっと注意しないとですね。","ENG":"Ah hah hah... I'll talk to her about it.","TWN":"哈哈哈……看來需要稍微注意一下呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아참, 다음 주에 저희가 새로 준비한 컨텐츠를 선보일 예정이에요.","JPN":"あ、来週は私たちが準備した新しいコンテンツを披露する予定です。","ENG":"Oh, I'm thinking of introducing the new content we've been working on next week.","TWN":"對了，下週我們將推出全新的內容。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그런가요? 어떤 컨텐츠죠?","JPN":"そうなんですね。どういうコンテンツですか？","ENG":"Really? What content might that be?","TWN":"是嗎？是什麼內容？"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"후후…… 저희가 준비한 최고 난이도의 퀘스트라 할 수 있죠.","JPN":"ふふ……最高難易度のクエストと言えますね。","ENG":"Fu fu... You can say that it's the most difficult quest we've made so far.","TWN":"呵呵……這可是我們準備的最高難度任務喔。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L35_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"관리국의 데이터를 제공받아 개발한 극악 난이도의 보스 몬스터에요.","JPN":"管理局のデータを提供してもらって開発した、最高難易度のボスモンスターです。","ENG":"It's a boss monster of an extreme difficulty level that we've developed with the data provided by the Administration.","TWN":"這是根據管理局的資料開發的地獄難度的BOSS。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"고마워요 선배. 덕분에 제가 기획에 개발까지 담당할 수 있었어요.","JPN":"ありがとうございます、先輩。先輩のおかげで私、企画から開発まで担当することができました。","ENG":"Thank you, Bora. I was able to take charge of planning and developing the whole thing thanks to you.","TWN":"謝謝你，前輩。多虧了你，我才能負責策劃和開發。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"했잖아…… 열심히. 당연한 결과야.","JPN":"やったから……一生懸命。当然の結果だよ。","ENG":"You worked... hard. The results are all because of you.","TWN":"你很努力……這是理所當然的結果。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후후, 열심히 해줘서 정말 고마워요.","JPN":"ふふ、頑張ってくださって私も感謝しています。","ENG":"Ha hah. Thank you for all your hard work.","TWN":"呵呵，還是要謝謝你辛勤地工作啦。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"처음 아카데미에 왔을 땐 조금 걱정했지만, 열정도 많고 수업 평가도 좋더군요.","JPN":"初めてアカデミーに来た頃は少し心配していましたけれど、熱情もあって、授業も好評でした。","ENG":"I was a little worried when you first came to the Academy, but you are very passionate and the class evaluations were also good.","TWN":"剛來學院的時候有點擔心，不過她很有熱情，課程評價也很好。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"앞으로도 잘 부탁드릴게요.","JPN":"これからもよろしくお願いしますね。","ENG":"I look forward to working with you furthermore.","TWN":"以後也請多多關照了。"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"하하, 당연하죠. 왜냐면 전 아카데미의 엘리트 교사…….","JPN":"あはは、当然です。なぜなら私はアカデミーのエリート教師……","ENG":"Hah hah, of course. I'm the Academy's elite teacher–","TWN":"哈哈，當然了。因為我是學院的精英教師……"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"으아악~ 그 녀석 때문에 나까지 말투가 이상해졌잖아……!","JPN":"うあああ～！　あいつのせいで私も変な口癖が移っちゃった……！","ENG":"NOOO! Her speech patterns are infecting me...!","TWN":"啊啊啊～都怪那傢伙，連我的說話方式都變得奇怪了……！"},"stage":{"bg":"CIRCLEROOM","bgm":"UI_BASE_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};